module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [9:0] accum;
reg [1:0] counter;
reg valid_out_reg;
assign data_out = accum;
assign valid_out = valid_out_reg;
always @(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		accum <= 10'd0;
		counter <= 2'd0;
		valid_out_reg <= 1'b0;
	end
	else begin
		if(valid_in == 1'b1) begin
			accum <= accum + data_in;
			counter <= counter + 1;
			if(counter == 2'd3) begin
				valid_out_reg <= 1'b1;
				counter <= 2'd0;
			end
			else begin
				valid_out_reg <= 1'b0;
			end
		end
		else begin
			valid_out_reg <= 1'b0;
		end
	end
end
endmodule
